panels.script:
await DASH.spec.ready;

function renderPeak() {
  const r = DASH.spec.panels.kpis.rows?.[0];
  if (r) document.getElementById('peak').textContent = r.max_hops + ' hops';
}
renderPeak();

function bind() {
  const st = DASH.spec.panels.longest;
  if (!st || !st.tbodyEl) return;
  st.tbodyEl.querySelectorAll('tr').forEach((tr, i) => {
    tr.classList.add('click');
    tr.addEventListener('click', () => show(st.rows[i]));
  });
}
bind();

async function show(row) {
  document.getElementById('dt').textContent =
    `${row.tail} on ${row.date} - ${row.carrier} (${row.hops} legs)`;
  document.getElementById('db').textContent = 'Loading legs...';
  const r = await DASH.spec.fetch('legs',
    `SELECT CRSDepTime, OriginCode, DestCode, Distance FROM ontime.fact_ontime WHERE FlightDate = '${row.date}' AND Tail_Number = '${row.tail}' ORDER BY CRSDepTime`);
  document.getElementById('db').innerHTML = r.rows.map(l => {
    const t = String(l.CRSDepTime).padStart(4,'0');
    return `${t.slice(0,2)}:${t.slice(2)} ${l.OriginCode} - ${l.DestCode} (${l.Distance} mi)`;
  }).join('<br>');
}

DASH.spec.on('panel:loaded', e => {
  if (e.id === 'kpis')    renderPeak();
  if (e.id === 'longest') bind();
});
